```
public void messageAckAsync(String topic, MessageId messageId, String
            eventId, java.util.function.Consumer<MessageId> successHandler,
                                java.util.function.Consumer<Exception> failHandler) {
        try {
            log.trace("acking msg. topic {} messageId {} eventId {}", topic, messageId, eventId);
            Consumer consumer = consumerMap.get(topic).getPulsarConsumer();
            consumer.acknowledgeAsync(messageId)
                    .handle((result, ex) -> {
                        if (ex == null) {
                            log.info("Message acked: {} topic {} envetId {}", messageId, topic, eventId);
                            successHandler.accept(messageId);
                        } else {
                            log.error("Error acking message to pulsar broker. errorMsg {} topic {} eventId {}", ex, topic, eventId);
                            failHandler.accept((Exception) ex);
                        }
                        return null;
                    });
        } catch (Exception e) {
            throw new RuntimeException("Ack failed. topic= " + topic + ", messageId= " + messageId + ", eventId= " + eventId);
        }
    }

